const express = require('express');
const app = express();
const bodyParser = require('body-parser');

app.use(bodyParser.json());

let plugins = [];

function loadPlugins() {
  const config = require('./config.json');
  if (config.plugins) {
    plugins = config.plugins;
  }
}

loadPlugins();

plugins.forEach(plugin => {
  try {
    let pluginCode;
    if (plugin.type === 'eval') {
      pluginCode = eval(plugin.code);
    } else if (plugin.type === 'require') {
      pluginCode = require(plugin.code);
    }

    const pluginInstance = new pluginCode();
    app.use(pluginInstance.middleware());
  } catch (error) {
    console.error(`Error loading plugin: ${error}`);
  }
});

app.use((req, res, next) => {
  plugins.forEach(plugin => {
    try {
      if (plugin.code && typeof plugin.code === 'function') {
        const result = plugin.code(req, res);
        if (result !== undefined) {
          return res.json(result);
        }
      }
    } catch (error) {
      console.error(`Error executing plugin: ${error}`);
    }
  });
  next();
});

app.use((err, req, res, next) => {
  console.error(err);
  res.status(500).json({ error: 'Internal Server Error' });
});

const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`API Gateway listening on port ${port}`);
});